{
  "customer_summary": {
    "summary": "The UVZ front‑end currently runs on Angular 18 and Pattern Library 11.3.1. Security patches for Angular 18 stop on 21 Nov 2025, after which only a paid \"Never‑Ending Support\" option is available. To keep the application secure, compliant and maintainable, the front‑end must be upgraded now to Angular 19 together with Pattern Library 12.6.0 and all related dependencies. If the upgrade is not performed, the system will become vulnerable to unpatched security issues and may eventually require costly support contracts or a forced migration later under tighter time pressure.",
    "impact_level": "high",
    "is_bug": false,
    "workaround": "Continue using Angular 18 by purchasing the paid Never‑Ending Support from the vendor, but this incurs additional cost and does not solve the underlying obsolescence.",
    "eta_category": "short"
  },
  "developer_context": {
    "big_picture": "UVZ is a web‑based application used by internal users of BNOTK (the client) to perform various operational tasks. The front‑end is built with Angular and consumes back‑end services (Java 17, Spring) via REST/GraphQL. This ticket addresses the need to move the front‑end from Angular 18 to Angular 19 and to update the internal Pattern Library from 11.3.1 to 12.6.0. The upgrade is required now because Angular 18 will lose free security updates after 21 Nov 2025, exposing the application to potential vulnerabilities and forcing a costly support contract. Without the upgrade, the product would become insecure, non‑compliant with internal security policies, and future upgrades would be more disruptive.",
    "scope_boundary": "IN: • Upgrade Angular core, CLI, and related packages to v19. • Upgrade Pattern Library to 12.6.0. • Update all listed runtime dependencies (node.js, TypeScript, bnotk/ds‑ng, ng‑bootstrap with its patch, ng‑select, ng‑option‑highlight, ag‑grid‑angular, ag‑grid‑community). • Adjust code for deprecations (e.g., vertical action bar usage, Karma removal if needed). • Remove any leftover Angular 18/PL 11 code that is not required by the new versions. OUT: • Back‑end Java services, database schema, CI/CD pipeline scripts unrelated to the front‑end build, non‑Angular UI components, and any third‑party libraries not listed in the acceptance criteria.",
    "classification_assessment": "",
    "classification_confidence": -1,
    "affected_components": [
      "UI Components (presentation layer)",
      "Pattern Library Integration Module (presentation layer)",
      "Vertical Action Bar Component (presentation layer)",
      "Angular Build Configuration (infrastructure layer)",
      "ng‑bootstrap wrapper components (presentation layer)"
    ],
    "context_boundaries": [
      {
        "category": "technology_constraint",
        "boundary": "Angular 19 requires TypeScript 5.x and a newer Node.js runtime than the current project (which uses TypeScript 4.9.5). The build must be updated accordingly, otherwise the compilation will fail.",
        "severity": "blocking",
        "source_facts": ["tech_versions.json: Angular 18.2.13", "tech_versions.json: TypeScript 4.9.5"]
      },
      {
        "category": "dependency_risk",
        "boundary": "Key UI libraries (ng‑bootstrap, ng‑select, ag‑grid) must have versions that are compatible with Angular 19. Some of the current versions may only support Angular 18, so a version bump or patch may be required.",
        "severity": "caution",
        "source_facts": ["issue_context: ng-bootstrap (Patch von UVZUSLNVV-5824) muss berücksichtigt werden", "issue_context: ag-grid-angular", "issue_context: ng-select/ng-select"]
      },
      {
        "category": "testing_constraint",
        "boundary": "Karma 6.4.3, used for unit tests, is deprecated in Angular 19. Tests will need to be migrated to a supported runner (e.g., Jest) or the Karma configuration must be updated to a compatible version.",
        "severity": "caution",
        "source_facts": ["tech_versions.json: Karma 6.4.3"]
      },
      {
        "category": "security_boundary",
        "boundary": "Angular 18 security updates end on 21 Nov 2025. Continuing to run the current version without paid support would leave the application exposed to known vulnerabilities.",
